export const goalCheckIns = pgTable("goal_check_ins", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	goalId: uuid("goal_id").notNull(),
	loggedValue: integer("logged_value").notNull(),
	notes: text(),
	loggedAt: timestamp("logged_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_goal_check_ins_logged_at").using("btree", table.goalId.asc().nullsLast().op("timestamptz_ops"), table.loggedAt.desc().nullsFirst().op("uuid_ops")),
	index("idx_goal_check_ins_tenant_goal").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops"), table.goalId.asc().nullsLast().op("uuid_ops")),
	foreignKey({
			columns: [table.goalId],
			foreignColumns: [chefGoals.id],
			name: "goal_check_ins_goal_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "goal_check_ins_tenant_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("Chefs manage own goal check-ins", { as: "permissive", for: "all", to: ["public"], using: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`, withCheck: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`  }),
	check("goal_check_ins_logged_value_check", sql`logged_value > 0`),
]);

