export const chefAutomationSettings = pgTable("chef_automation_settings", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	followUpRemindersEnabled: boolean("follow_up_reminders_enabled").default(true).notNull(),
	followUpReminderIntervalHours: integer("follow_up_reminder_interval_hours").default(48).notNull(),
	noResponseAlertsEnabled: boolean("no_response_alerts_enabled").default(true).notNull(),
	noResponseThresholdDays: integer("no_response_threshold_days").default(3).notNull(),
	eventApproachingAlertsEnabled: boolean("event_approaching_alerts_enabled").default(true).notNull(),
	eventApproachingHours: integer("event_approaching_hours").default(48).notNull(),
	inquiryAutoExpiryEnabled: boolean("inquiry_auto_expiry_enabled").default(true).notNull(),
	inquiryExpiryDays: integer("inquiry_expiry_days").default(30).notNull(),
	quoteAutoExpiryEnabled: boolean("quote_auto_expiry_enabled").default(true).notNull(),
	clientEventRemindersEnabled: boolean("client_event_reminders_enabled").default(true).notNull(),
	timeTrackingRemindersEnabled: boolean("time_tracking_reminders_enabled").default(true).notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	receiptUploadRemindersEnabled: boolean("receipt_upload_reminders_enabled").default(true).notNull(),
	closureDeadlineAlertsEnabled: boolean("closure_deadline_alerts_enabled").default(true).notNull(),
	closureDeadlineDays: integer("closure_deadline_days").default(3).notNull(),
	weeklySummaryEnabled: boolean("weekly_summary_enabled").default(false).notNull(),
	inquiryAutoResponseTemplate: text("inquiry_auto_response_template"),
	autoResponseTemplateEnabled: boolean("auto_response_template_enabled").default(false).notNull(),
	paymentReminderEnabled: boolean("payment_reminder_enabled").default(true).notNull(),
	paymentReminderDaysBefore: integer("payment_reminder_days_before").default(2).notNull(),
	paymentOverdueAlertEnabled: boolean("payment_overdue_alert_enabled").default(true).notNull(),
	paymentOverdueAlertDaysAfter: integer("payment_overdue_alert_days_after").default(1).notNull(),
	defaultDepositEnabled: boolean("default_deposit_enabled").default(false).notNull(),
	defaultDepositType: text("default_deposit_type").default('percentage').notNull(),
	defaultDepositPercentage: integer("default_deposit_percentage").default(0).notNull(),
	defaultDepositAmountCents: integer("default_deposit_amount_cents").default(0).notNull(),
	eventReminder30DEnabled: boolean("event_reminder_30d_enabled").default(true).notNull(),
	eventReminder14DEnabled: boolean("event_reminder_14d_enabled").default(true).notNull(),
	eventReminder7DEnabled: boolean("event_reminder_7d_enabled").default(true).notNull(),
	eventReminder2DEnabled: boolean("event_reminder_2d_enabled").default(true).notNull(),
	eventReminder1DEnabled: boolean("event_reminder_1d_enabled").default(true).notNull(),
}, (table) => [
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "chef_automation_settings_tenant_id_fkey"
		}).onDelete("cascade"),
	unique("chef_automation_settings_tenant_id_key").on(table.tenantId),
	pgPolicy("chef_automation_settings_chef_rw", { as: "permissive", for: "all", to: ["authenticated"], using: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`, withCheck: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`  }),
	pgPolicy("chef_automation_settings_service_all", { as: "permissive", for: "all", to: ["service_role"] }),
	check("chef_automation_settings_default_deposit_amount_cents_check", sql`default_deposit_amount_cents >= 0`),
	check("chef_automation_settings_default_deposit_percentage_check", sql`(default_deposit_percentage >= 0) AND (default_deposit_percentage <= 100)`),
	check("chef_automation_settings_default_deposit_type_check", sql`default_deposit_type = ANY (ARRAY['percentage'::text, 'fixed'::text])`),
	check("chef_automation_settings_event_approaching_hours_check", sql`(event_approaching_hours >= 1) AND (event_approaching_hours <= 168)`),
	check("chef_automation_settings_follow_up_reminder_interval_hour_check", sql`(follow_up_reminder_interval_hours >= 1) AND (follow_up_reminder_interval_hours <= 336)`),
	check("chef_automation_settings_inquiry_expiry_days_check", sql`(inquiry_expiry_days >= 7) AND (inquiry_expiry_days <= 365)`),
	check("chef_automation_settings_no_response_threshold_days_check", sql`(no_response_threshold_days >= 1) AND (no_response_threshold_days <= 30)`),
]);

export const guestMessages = pgTable("guest_messages", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	eventId: uuid("event_id").notNull(),
	guestId: uuid("guest_id"),
	guestName: text("guest_name").notNull(),
	message: text().notNull(),
	emoji: text(),
	isVisible: boolean("is_visible").default(true).notNull(),
	isPinned: boolean("is_pinned").default(false).notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	guestToken: text("guest_token"),
	readAt: timestamp("read_at", { withTimezone: true, mode: 'string' }),
}, (table) => [
	index("idx_guest_messages_event").using("btree", table.eventId.asc().nullsLast().op("timestamptz_ops"), table.isVisible.asc().nullsLast().op("uuid_ops"), table.createdAt.desc().nullsFirst().op("timestamptz_ops")),
	index("idx_guest_messages_guest").using("btree", table.guestId.asc().nullsLast().op("uuid_ops")),
	index("idx_guest_messages_tenant").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops")),
	index("idx_guest_messages_unread").using("btree", table.eventId.asc().nullsLast().op("uuid_ops")).where(sql`(read_at IS NULL)`),
	foreignKey({
			columns: [table.eventId],
			foreignColumns: [events.id],
			name: "guest_messages_event_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.guestId],
			foreignColumns: [eventGuests.id],
			name: "guest_messages_guest_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "guest_messages_tenant_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("guest_messages_public_read", { as: "permissive", for: "select", to: ["public"], using: sql`(is_visible = true)` }),
	pgPolicy("guest_messages_chef_read_all", { as: "permissive", for: "select", to: ["public"] }),
	pgPolicy("guest_messages_chef_update", { as: "permissive", for: "update", to: ["public"] }),
	pgPolicy("guest_messages_chef_delete", { as: "permissive", for: "delete", to: ["public"] }),
	pgPolicy("guest_messages_chef_all", { as: "permissive", for: "all", to: ["authenticated"] }),
	pgPolicy("guest_messages_public_insert", { as: "permissive", for: "insert", to: ["public"] }),
	check("guest_messages_message_check", sql`char_length(message) <= 500`),
]);

