export const chefCalendarEntries = pgTable("chef_calendar_entries", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	chefId: uuid("chef_id").notNull(),
	entryType: chefCalendarEntryType("entry_type").notNull(),
	title: text().notNull(),
	description: text(),
	startDate: date("start_date").notNull(),
	endDate: date("end_date").notNull(),
	allDay: boolean("all_day").default(true).notNull(),
	startTime: time("start_time"),
	endTime: time("end_time"),
	blocksBookings: boolean("blocks_bookings").default(true).notNull(),
	isRevenueGenerating: boolean("is_revenue_generating").default(false).notNull(),
	revenueType: text("revenue_type"),
	expectedRevenueCents: integer("expected_revenue_cents"),
	actualRevenueCents: integer("actual_revenue_cents"),
	revenueNotes: text("revenue_notes"),
	isPublic: boolean("is_public").default(false).notNull(),
	publicNote: text("public_note"),
	colorOverride: text("color_override"),
	isRecurring: boolean("is_recurring").default(false).notNull(),
	recurrenceRule: text("recurrence_rule"),
	recurrenceEndDate: date("recurrence_end_date"),
	isPrivate: boolean("is_private").default(true).notNull(),
	isCompleted: boolean("is_completed").default(false).notNull(),
	completedAt: timestamp("completed_at", { withTimezone: true, mode: 'string' }),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_cal_entries_blocking").using("btree", table.chefId.asc().nullsLast().op("date_ops"), table.startDate.asc().nullsLast().op("date_ops")).where(sql`(blocks_bookings = true)`),
	index("idx_cal_entries_chef_date").using("btree", table.chefId.asc().nullsLast().op("uuid_ops"), table.startDate.asc().nullsLast().op("uuid_ops"), table.endDate.asc().nullsLast().op("date_ops")),
	index("idx_cal_entries_chef_type").using("btree", table.chefId.asc().nullsLast().op("uuid_ops"), table.entryType.asc().nullsLast().op("enum_ops")),
	index("idx_cal_entries_public").using("btree", table.chefId.asc().nullsLast().op("date_ops"), table.startDate.asc().nullsLast().op("date_ops")).where(sql`(is_public = true)`),
	index("idx_cal_entries_revenue").using("btree", table.chefId.asc().nullsLast().op("uuid_ops")).where(sql`(is_revenue_generating = true)`),
	foreignKey({
			columns: [table.chefId],
			foreignColumns: [chefs.id],
			name: "chef_calendar_entries_chef_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("chef owns calendar entries", { as: "permissive", for: "all", to: ["public"], using: sql`((get_current_user_role() = 'chef'::user_role) AND (chef_id = get_current_tenant_id()))`, withCheck: sql`((get_current_user_role() = 'chef'::user_role) AND (chef_id = get_current_tenant_id()))`  }),
	pgPolicy("public can view public calendar signals", { as: "permissive", for: "select", to: ["public"] }),
	check("chef_calendar_entries_revenue_type_check", sql`revenue_type = ANY (ARRAY['income'::text, 'promotional'::text])`),
	check("end_after_start", sql`end_date >= start_date`),
	check("revenue_type_requires_flag", sql`(revenue_type IS NULL) OR (is_revenue_generating = true)`),
	check("time_range_valid", sql`(all_day = true) OR ((start_time IS NOT NULL) AND (end_time IS NOT NULL) AND (end_time > start_time))`),
]);

