export const dietaryChangeLog = pgTable("dietary_change_log", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	chefId: uuid("chef_id").notNull(),
	clientId: uuid("client_id").notNull(),
	changeType: text("change_type").notNull(),
	fieldName: text("field_name").notNull(),
	oldValue: text("old_value"),
	newValue: text("new_value"),
	severity: text(),
	acknowledged: boolean().default(false).notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_dietary_change_log_chef_ack").using("btree", table.chefId.asc().nullsLast().op("timestamptz_ops"), table.acknowledged.asc().nullsLast().op("timestamptz_ops"), table.createdAt.desc().nullsFirst().op("timestamptz_ops")),
	index("idx_dietary_change_log_chef_type").using("btree", table.chefId.asc().nullsLast().op("text_ops"), table.changeType.asc().nullsLast().op("text_ops"), table.createdAt.desc().nullsFirst().op("text_ops")),
	index("idx_dietary_change_log_client").using("btree", table.clientId.asc().nullsLast().op("timestamptz_ops"), table.createdAt.desc().nullsFirst().op("timestamptz_ops")),
	foreignKey({
			columns: [table.chefId],
			foreignColumns: [chefs.id],
			name: "dietary_change_log_chef_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.clientId],
			foreignColumns: [clients.id],
			name: "dietary_change_log_client_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("dietary_change_log_chef_select", { as: "permissive", for: "select", to: ["public"], using: sql`((get_current_user_role() = 'chef'::user_role) AND (chef_id = get_current_tenant_id()))` }),
	pgPolicy("dietary_change_log_chef_insert", { as: "permissive", for: "insert", to: ["public"] }),
	pgPolicy("dietary_change_log_chef_update", { as: "permissive", for: "update", to: ["public"] }),
	pgPolicy("dietary_change_log_chef_delete", { as: "permissive", for: "delete", to: ["public"] }),
	check("dietary_change_log_change_type_check", sql`change_type = ANY (ARRAY['allergy_added'::text, 'allergy_removed'::text, 'restriction_added'::text, 'restriction_removed'::text, 'preference_updated'::text, 'note_updated'::text])`),
	check("dietary_change_log_severity_check", sql`severity = ANY (ARRAY['critical'::text, 'warning'::text, 'info'::text])`),
]);

export const dietaryConflictAlerts = pgTable("dietary_conflict_alerts", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	eventId: uuid("event_id").notNull(),
	chefId: uuid("chef_id").notNull(),
	guestName: text("guest_name").notNull(),
	allergy: text().notNull(),
	conflictingDish: text("conflicting_dish").notNull(),
	severity: text().default('warning').notNull(),
	acknowledged: boolean().default(false).notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_dietary_conflicts_event").using("btree", table.eventId.asc().nullsLast().op("uuid_ops"), table.chefId.asc().nullsLast().op("uuid_ops")),
	foreignKey({
			columns: [table.chefId],
			foreignColumns: [chefs.id],
			name: "dietary_conflict_alerts_chef_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.eventId],
			foreignColumns: [events.id],
			name: "dietary_conflict_alerts_event_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("dca_chef_select", { as: "permissive", for: "select", to: ["public"], using: sql`((get_current_user_role() = 'chef'::user_role) AND (chef_id = get_current_tenant_id()))` }),
	pgPolicy("dca_chef_insert", { as: "permissive", for: "insert", to: ["public"] }),
	pgPolicy("dca_chef_update", { as: "permissive", for: "update", to: ["public"] }),
	pgPolicy("dca_chef_delete", { as: "permissive", for: "delete", to: ["public"] }),
	check("dietary_conflict_alerts_severity_check", sql`severity = ANY (ARRAY['critical'::text, 'warning'::text, 'info'::text])`),
]);

export const dishFeedback = pgTable("dish_feedback", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	dishId: uuid("dish_id").notNull(),
	tenantId: uuid("tenant_id").notNull(),
	eventId: uuid("event_id"),
	rating: integer(),
	clientReaction: text("client_reaction"),
	executionNotes: text("execution_notes"),
	wouldServeAgain: boolean("would_serve_again").default(true),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_dish_feedback_dish").using("btree", table.dishId.asc().nullsLast().op("uuid_ops")),
	index("idx_dish_feedback_tenant").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops")),
	foreignKey({
			columns: [table.dishId],
			foreignColumns: [dishIndex.id],
			name: "dish_feedback_dish_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.eventId],
			foreignColumns: [events.id],
			name: "dish_feedback_event_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "dish_feedback_tenant_id_fkey"
		}),
	pgPolicy("chef_dish_feedback_all", { as: "permissive", for: "all", to: ["public"], using: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))` }),
	check("dish_feedback_rating_check", sql`(rating >= 1) AND (rating <= 5)`),
]);

export const dishIndex = pgTable("dish_index", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	name: text().notNull(),
	canonicalName: text("canonical_name").notNull(),
	course: text().notNull(),
	description: text(),
	dietaryTags: text("dietary_tags").array().default([""]),
	allergenFlags: text("allergen_flags").array().default([""]),
	prepComplexity: dishPrepComplexity("prep_complexity"),
	canPrepAhead: boolean("can_prep_ahead"),
	specialEquipment: text("special_equipment").array().default([""]),
	platingDifficulty: dishPlatingDifficulty("plating_difficulty"),
	photoStoragePath: text("photo_storage_path"),
	linkedRecipeId: uuid("linked_recipe_id"),
	firstServed: date("first_served"),
	lastServed: date("last_served"),
	timesServed: integer("times_served").default(0).notNull(),
	isSignature: boolean("is_signature").default(false).notNull(),
	rotationStatus: dishRotationStatus("rotation_status").default('active').notNull(),
	retiredAt: timestamp("retired_at", { withTimezone: true, mode: 'string' }),
	retirementReason: text("retirement_reason"),
	seasonAffinity: text("season_affinity").array().default([""]),
	tags: text().array().default([""]),
	notes: text(),
	dna: jsonb().default({}),
	archived: boolean().default(false).notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_dish_index_canonical").using("btree", table.tenantId.asc().nullsLast().op("text_ops"), table.canonicalName.asc().nullsLast().op("uuid_ops")),
	index("idx_dish_index_course").using("btree", table.tenantId.asc().nullsLast().op("text_ops"), table.course.asc().nullsLast().op("uuid_ops")),
	index("idx_dish_index_recipe").using("btree", table.linkedRecipeId.asc().nullsLast().op("uuid_ops")).where(sql`(linked_recipe_id IS NOT NULL)`),
	index("idx_dish_index_rotation").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops"), table.rotationStatus.asc().nullsLast().op("uuid_ops")).where(sql`(archived = false)`),
	index("idx_dish_index_signature").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops")).where(sql`(is_signature = true)`),
	index("idx_dish_index_tenant").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops")),
	foreignKey({
			columns: [table.linkedRecipeId],
			foreignColumns: [recipes.id],
			name: "dish_index_linked_recipe_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "dish_index_tenant_id_fkey"
		}),
	unique("dish_index_tenant_id_canonical_name_course_key").on(table.tenantId, table.canonicalName, table.course),
	pgPolicy("chef_dish_index_all", { as: "permissive", for: "all", to: ["public"], using: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))` }),
]);

export const dishVariations = pgTable("dish_variations", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	parentDishId: uuid("parent_dish_id").notNull(),
	variantDishId: uuid("variant_dish_id").notNull(),
	relationship: text().default('variation').notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	foreignKey({
			columns: [table.parentDishId],
			foreignColumns: [dishIndex.id],
			name: "dish_variations_parent_dish_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "dish_variations_tenant_id_fkey"
		}),
	foreignKey({
			columns: [table.variantDishId],
			foreignColumns: [dishIndex.id],
			name: "dish_variations_variant_dish_id_fkey"
		}).onDelete("cascade"),
	unique("dish_variations_parent_dish_id_variant_dish_id_key").on(table.parentDishId, table.variantDishId),
	pgPolicy("chef_dish_variations_all", { as: "permissive", for: "all", to: ["public"], using: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))` }),
	check("dish_variations_check", sql`parent_dish_id <> variant_dish_id`),
]);

export const displayCaseItems = pgTable("display_case_items", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	productName: text("product_name").notNull(),
	category: text().default('pastry').notNull(),
	currentQuantity: integer("current_quantity").default(0).notNull(),
	parLevel: integer("par_level").default(0).notNull(),
	priceCents: integer("price_cents").notNull(),
	bakedAt: timestamp("baked_at", { withTimezone: true, mode: 'string' }),
	shelfLifeHours: integer("shelf_life_hours"),
	allergens: text().array(),
	isActive: boolean("is_active").default(true).notNull(),
	lastRestocked: timestamp("last_restocked", { withTimezone: true, mode: 'string' }),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_display_case_items_tenant").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops")),
	index("idx_display_case_items_tenant_active").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops")).where(sql`(is_active = true)`),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "display_case_items_tenant_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("Chefs can manage their own display case items", { as: "permissive", for: "all", to: ["public"], using: sql`((tenant_id = auth.uid()) OR (EXISTS ( SELECT 1
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.entity_id = display_case_items.tenant_id)))))`, withCheck: sql`((tenant_id = auth.uid()) OR (EXISTS ( SELECT 1
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.entity_id = display_case_items.tenant_id)))))`  }),
	check("display_case_items_category_check", sql`category = ANY (ARRAY['bread'::text, 'pastry'::text, 'cake'::text, 'cookie'::text, 'savory'::text, 'drink'::text, 'other'::text])`),
]);

