export const giftCards = pgTable("gift_cards", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	code: text().notNull(),
	initialValueCents: integer("initial_value_cents").notNull(),
	currentBalanceCents: integer("current_balance_cents").notNull(),
	purchaserName: text("purchaser_name"),
	purchaserEmail: text("purchaser_email"),
	recipientName: text("recipient_name"),
	recipientEmail: text("recipient_email"),
	message: text(),
	status: text().default('active').notNull(),
	expiresAt: date("expires_at"),
	issuedAt: timestamp("issued_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_gift_cards_tenant_code").using("btree", table.tenantId.asc().nullsLast().op("text_ops"), table.code.asc().nullsLast().op("text_ops")),
	index("idx_gift_cards_tenant_status").using("btree", table.tenantId.asc().nullsLast().op("text_ops"), table.status.asc().nullsLast().op("text_ops")),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "gift_cards_tenant_id_fkey"
		}).onDelete("cascade"),
	unique("gift_cards_tenant_id_code_key").on(table.tenantId, table.code),
	pgPolicy("gift_cards_tenant_isolation", { as: "permissive", for: "all", to: ["public"], using: sql`(tenant_id = auth.uid())` }),
	check("gift_cards_status_check", sql`status = ANY (ARRAY['active'::text, 'redeemed'::text, 'expired'::text, 'cancelled'::text])`),
]);

export const goalClientSuggestions = pgTable("goal_client_suggestions", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	goalId: uuid("goal_id").notNull(),
	clientId: uuid("client_id").notNull(),
	reason: text().notNull(),
	rank: integer().default(0).notNull(),
	status: text().default('pending').notNull(),
	contactedAt: timestamp("contacted_at", { withTimezone: true, mode: 'string' }),
	bookedEventId: uuid("booked_event_id"),
	daysDormant: integer("days_dormant"),
	avgSpendCents: integer("avg_spend_cents"),
	lifetimeValueCents: integer("lifetime_value_cents"),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_goal_client_suggestions_tenant_goal").using("btree", table.tenantId.asc().nullsLast().op("text_ops"), table.goalId.asc().nullsLast().op("text_ops"), table.status.asc().nullsLast().op("text_ops")),
	foreignKey({
			columns: [table.bookedEventId],
			foreignColumns: [events.id],
			name: "goal_client_suggestions_booked_event_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.clientId],
			foreignColumns: [clients.id],
			name: "goal_client_suggestions_client_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.goalId],
			foreignColumns: [chefGoals.id],
			name: "goal_client_suggestions_goal_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "goal_client_suggestions_tenant_id_fkey"
		}).onDelete("cascade"),
	unique("goal_client_suggestions_unique").on(table.goalId, table.clientId),
	pgPolicy("goal_client_suggestions_select", { as: "permissive", for: "select", to: ["public"], using: sql`(tenant_id = get_current_tenant_id())` }),
	pgPolicy("goal_client_suggestions_insert", { as: "permissive", for: "insert", to: ["public"] }),
	pgPolicy("goal_client_suggestions_update", { as: "permissive", for: "update", to: ["public"] }),
	check("goal_client_suggestions_status_check", sql`status = ANY (ARRAY['pending'::text, 'contacted'::text, 'booked'::text, 'declined'::text, 'dismissed'::text])`),
]);

export const goalSnapshots = pgTable("goal_snapshots", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	goalId: uuid("goal_id").notNull(),
	snapshotDate: date("snapshot_date").notNull(),
	snapshotMonth: text("snapshot_month").notNull(),
	currentValue: integer("current_value").default(0).notNull(),
	targetValue: integer("target_value").notNull(),
	gapValue: integer("gap_value").default(0).notNull(),
	progressPercent: integer("progress_percent").default(0).notNull(),
	realizedCents: integer("realized_cents"),
	projectedCents: integer("projected_cents"),
	avgBookingValueCents: integer("avg_booking_value_cents"),
	eventsNeeded: integer("events_needed"),
	pricingScenarios: jsonb("pricing_scenarios").default([]).notNull(),
	clientSuggestionsJson: jsonb("client_suggestions_json").default([]).notNull(),
	computedAt: timestamp("computed_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	index("idx_goal_snapshots_goal_date").using("btree", table.goalId.asc().nullsLast().op("date_ops"), table.snapshotDate.desc().nullsFirst().op("uuid_ops")),
	index("idx_goal_snapshots_tenant_month").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops"), table.snapshotMonth.desc().nullsFirst().op("text_ops")),
	foreignKey({
			columns: [table.goalId],
			foreignColumns: [chefGoals.id],
			name: "goal_snapshots_goal_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "goal_snapshots_tenant_id_fkey"
		}).onDelete("cascade"),
	unique("goal_snapshots_unique_goal_date").on(table.goalId, table.snapshotDate),
	pgPolicy("goal_snapshots_select", { as: "permissive", for: "select", to: ["public"], using: sql`(tenant_id = get_current_tenant_id())` }),
	pgPolicy("goal_snapshots_insert", { as: "permissive", for: "insert", to: ["public"] }),
]);

export const googleConnections = pgTable("google_connections", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	chefId: uuid("chef_id").notNull(),
	tenantId: uuid("tenant_id").notNull(),
	accessToken: text("access_token"),
	refreshToken: text("refresh_token"),
	tokenExpiresAt: timestamp("token_expires_at", { withTimezone: true, mode: 'string' }),
	connectedEmail: text("connected_email"),
	gmailConnected: boolean("gmail_connected").default(false).notNull(),
	calendarConnected: boolean("calendar_connected").default(false).notNull(),
	scopes: text().array().default([""]).notNull(),
	gmailHistoryId: text("gmail_history_id"),
	gmailLastSyncAt: timestamp("gmail_last_sync_at", { withTimezone: true, mode: 'string' }),
	gmailSyncErrors: integer("gmail_sync_errors").default(0).notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	historicalScanEnabled: boolean("historical_scan_enabled").default(false).notNull(),
	historicalScanStatus: text("historical_scan_status").default('idle').notNull(),
	historicalScanPageToken: text("historical_scan_page_token"),
	historicalScanTotalProcessed: integer("historical_scan_total_processed").default(0).notNull(),
	historicalScanLookbackDays: integer("historical_scan_lookback_days").default(0).notNull(),
	historicalScanStartedAt: timestamp("historical_scan_started_at", { withTimezone: true, mode: 'string' }),
	historicalScanCompletedAt: timestamp("historical_scan_completed_at", { withTimezone: true, mode: 'string' }),
	historicalScanLastRunAt: timestamp("historical_scan_last_run_at", { withTimezone: true, mode: 'string' }),
	historicalScanTotalSeen: integer("historical_scan_total_seen").default(0).notNull(),
	historicalScanResultSizeEstimate: integer("historical_scan_result_size_estimate"),
	historicalScanIncludeSpamTrash: boolean("historical_scan_include_spam_trash").default(true).notNull(),
}, (table) => [
	index("idx_google_connections_gmail_active").using("btree", table.gmailConnected.asc().nullsLast().op("bool_ops")).where(sql`(gmail_connected = true)`),
	foreignKey({
			columns: [table.chefId],
			foreignColumns: [chefs.id],
			name: "google_connections_chef_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "google_connections_tenant_id_fkey"
		}).onDelete("cascade"),
	unique("unique_chef_google").on(table.chefId),
	pgPolicy("Chefs manage own google connection", { as: "permissive", for: "all", to: ["public"], using: sql`(chef_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`, withCheck: sql`(chef_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`  }),
]);

export const groceryPriceEntries = pgTable("grocery_price_entries", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	chefId: uuid("chef_id").notNull(),
	ingredientName: text("ingredient_name").notNull(),
	unit: text().notNull(),
	priceCents: integer("price_cents").notNull(),
	quantity: numeric().default('1').notNull(),
	storeName: text("store_name"),
	receiptDate: date("receipt_date").default(sql`CURRENT_DATE`).notNull(),
	notes: text(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow(),
}, (table) => [
	index("idx_grocery_price_chef_ingredient").using("btree", table.chefId.asc().nullsLast().op("text_ops"), table.ingredientName.asc().nullsLast().op("text_ops")),
	index("idx_grocery_price_chef_store").using("btree", table.chefId.asc().nullsLast().op("text_ops"), table.storeName.asc().nullsLast().op("text_ops")),
	foreignKey({
			columns: [table.chefId],
			foreignColumns: [chefs.id],
			name: "grocery_price_entries_chef_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("Chefs can view own price entries", { as: "permissive", for: "select", to: ["public"], using: sql`(chef_id = auth.uid())` }),
	pgPolicy("Chefs can insert own price entries", { as: "permissive", for: "insert", to: ["public"] }),
	pgPolicy("Chefs can update own price entries", { as: "permissive", for: "update", to: ["public"] }),
	pgPolicy("Chefs can delete own price entries", { as: "permissive", for: "delete", to: ["public"] }),
]);

export const groceryPriceQuoteItems = pgTable("grocery_price_quote_items", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	quoteId: uuid("quote_id").notNull(),
	ingredientId: uuid("ingredient_id"),
	ingredientName: text("ingredient_name").notNull(),
	quantity: numeric(),
	unit: text(),
	spoonacularPriceCents: integer("spoonacular_price_cents"),
	krogerPriceCents: integer("kroger_price_cents"),
	averagePriceCents: integer("average_price_cents"),
	mealmePriceCents: integer("mealme_price_cents"),
	manualPriceCents: integer("manual_price_cents"),
	isManualOverride: boolean("is_manual_override").default(false).notNull(),
	sourceLabel: text("source_label"),
}, (table) => [
	index("grocery_price_quote_items_quote_idx").using("btree", table.quoteId.asc().nullsLast().op("uuid_ops")),
	index("idx_gqpi_ingredient").using("btree", table.ingredientId.asc().nullsLast().op("uuid_ops"), table.quoteId.asc().nullsLast().op("uuid_ops")),
	foreignKey({
			columns: [table.ingredientId],
			foreignColumns: [ingredients.id],
			name: "grocery_price_quote_items_ingredient_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.quoteId],
			foreignColumns: [groceryPriceQuotes.id],
			name: "grocery_price_quote_items_quote_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("chef_own_quote_items", { as: "permissive", for: "all", to: ["public"], using: sql`(quote_id IN ( SELECT grocery_price_quotes.id
   FROM grocery_price_quotes
  WHERE (grocery_price_quotes.tenant_id IN ( SELECT user_roles.entity_id
           FROM user_roles
          WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))))` }),
]);

export const groceryPriceQuotes = pgTable("grocery_price_quotes", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	eventId: uuid("event_id").notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	ingredientCount: integer("ingredient_count"),
	spoonacularTotalCents: integer("spoonacular_total_cents"),
	krogerTotalCents: integer("kroger_total_cents"),
	averageTotalCents: integer("average_total_cents"),
	instacartLink: text("instacart_link"),
	status: text().default('pending').notNull(),
	mealmeTotalCents: integer("mealme_total_cents"),
	actualGroceryCostCents: integer("actual_grocery_cost_cents"),
	accuracyDeltaPct: numeric("accuracy_delta_pct", { precision: 6, scale:  2 }),
	actualCostLoggedAt: timestamp("actual_cost_logged_at", { withTimezone: true, mode: 'string' }),
}, (table) => [
	index("grocery_price_quotes_event_idx").using("btree", table.tenantId.asc().nullsLast().op("timestamptz_ops"), table.eventId.asc().nullsLast().op("timestamptz_ops"), table.createdAt.desc().nullsFirst().op("uuid_ops")),
	index("idx_grocery_quotes_tenant_accuracy").using("btree", table.tenantId.asc().nullsLast().op("int4_ops"), table.actualGroceryCostCents.asc().nullsLast().op("int4_ops")).where(sql`(actual_grocery_cost_cents IS NOT NULL)`),
	foreignKey({
			columns: [table.eventId],
			foreignColumns: [events.id],
			name: "grocery_price_quotes_event_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "grocery_price_quotes_tenant_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("chef_own_quotes", { as: "permissive", for: "all", to: ["public"], using: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))` }),
	check("grocery_price_quotes_status_check", sql`status = ANY (ARRAY['pending'::text, 'complete'::text, 'partial'::text, 'failed'::text])`),
]);

