export const googleMailboxes = pgTable("google_mailboxes", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	chefId: uuid("chef_id").notNull(),
	tenantId: uuid("tenant_id").notNull(),
	email: text().notNull(),
	normalizedEmail: text("normalized_email").notNull(),
	accessToken: text("access_token"),
	refreshToken: text("refresh_token"),
	tokenExpiresAt: timestamp("token_expires_at", { withTimezone: true, mode: 'string' }),
	scopes: text().array().default([""]).notNull(),
	gmailConnected: boolean("gmail_connected").default(false).notNull(),
	gmailHistoryId: text("gmail_history_id"),
	gmailLastSyncAt: timestamp("gmail_last_sync_at", { withTimezone: true, mode: 'string' }),
	gmailSyncErrors: integer("gmail_sync_errors").default(0).notNull(),
	historicalScanEnabled: boolean("historical_scan_enabled").default(false).notNull(),
	historicalScanIncludeSpamTrash: boolean("historical_scan_include_spam_trash").default(true).notNull(),
	historicalScanStatus: text("historical_scan_status").default('idle').notNull(),
	historicalScanPageToken: text("historical_scan_page_token"),
	historicalScanTotalProcessed: integer("historical_scan_total_processed").default(0).notNull(),
	historicalScanTotalSeen: integer("historical_scan_total_seen").default(0).notNull(),
	historicalScanResultSizeEstimate: integer("historical_scan_result_size_estimate"),
	historicalScanLookbackDays: integer("historical_scan_lookback_days").default(0).notNull(),
	historicalScanStartedAt: timestamp("historical_scan_started_at", { withTimezone: true, mode: 'string' }),
	historicalScanCompletedAt: timestamp("historical_scan_completed_at", { withTimezone: true, mode: 'string' }),
	historicalScanLastRunAt: timestamp("historical_scan_last_run_at", { withTimezone: true, mode: 'string' }),
	isPrimary: boolean("is_primary").default(false).notNull(),
	isActive: boolean("is_active").default(true).notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
}, (table) => [
	uniqueIndex("idx_google_mailboxes_active_email").using("btree", table.normalizedEmail.asc().nullsLast().op("text_ops")).where(sql`((gmail_connected = true) AND (is_active = true))`),
	index("idx_google_mailboxes_chef").using("btree", table.chefId.asc().nullsLast().op("timestamptz_ops"), table.isActive.asc().nullsLast().op("uuid_ops"), table.isPrimary.desc().nullsFirst().op("timestamptz_ops"), table.createdAt.asc().nullsLast().op("uuid_ops")),
	index("idx_google_mailboxes_gmail_active").using("btree", table.gmailConnected.asc().nullsLast().op("bool_ops"), table.isActive.asc().nullsLast().op("bool_ops")).where(sql`((gmail_connected = true) AND (is_active = true))`),
	uniqueIndex("idx_google_mailboxes_primary_one").using("btree", table.chefId.asc().nullsLast().op("uuid_ops")).where(sql`((is_primary = true) AND (is_active = true))`),
	index("idx_google_mailboxes_scan_active").using("btree", table.historicalScanEnabled.asc().nullsLast().op("bool_ops"), table.gmailConnected.asc().nullsLast().op("bool_ops"), table.isActive.asc().nullsLast().op("bool_ops")).where(sql`((historical_scan_enabled = true) AND (gmail_connected = true) AND (is_active = true))`),
	foreignKey({
			columns: [table.chefId],
			foreignColumns: [chefs.id],
			name: "google_mailboxes_chef_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "google_mailboxes_tenant_id_fkey"
		}).onDelete("cascade"),
	unique("unique_google_mailbox_per_chef").on(table.chefId, table.normalizedEmail),
	pgPolicy("Chefs manage own google mailboxes", { as: "permissive", for: "all", to: ["public"], using: sql`(chef_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`, withCheck: sql`(chef_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`  }),
	pgPolicy("Service role manages google mailboxes", { as: "permissive", for: "all", to: ["public"] }),
	check("google_mailbox_status_check", sql`historical_scan_status = ANY (ARRAY['idle'::text, 'in_progress'::text, 'completed'::text, 'paused'::text])`),
]);

