export const productProjections = pgTable("product_projections", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	recipeId: uuid("recipe_id"),
	menuId: uuid("menu_id"),
	name: text().notNull(),
	description: text(),
	category: text(),
	sku: text(),
	barcode: text(),
	imageUrl: text("image_url"),
	priceCents: integer("price_cents").notNull(),
	costCents: integer("cost_cents"),
	taxClass: taxClass("tax_class").default('standard').notNull(),
	trackInventory: boolean("track_inventory").default(false).notNull(),
	availableQty: integer("available_qty"),
	lowStockThreshold: integer("low_stock_threshold"),
	isActive: boolean("is_active").default(true).notNull(),
	sortOrder: integer("sort_order").default(0).notNull(),
	tags: text().array().default([""]),
	modifiers: jsonb().default([]),
	dietaryTags: text("dietary_tags").array().default([""]),
	allergenFlags: text("allergen_flags").array().default([""]),
	snapshotAt: timestamp("snapshot_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	sourceVersion: integer("source_version").default(1),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	updatedAt: timestamp("updated_at", { withTimezone: true, mode: 'string' }).defaultNow().notNull(),
	stationId: uuid("station_id"),
}, (table) => [
	index("idx_product_projections_active").using("btree", table.tenantId.asc().nullsLast().op("bool_ops"), table.isActive.asc().nullsLast().op("bool_ops")).where(sql`(is_active = true)`),
	index("idx_product_projections_category").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops"), table.category.asc().nullsLast().op("text_ops")),
	index("idx_product_projections_sku").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops"), table.sku.asc().nullsLast().op("text_ops")).where(sql`(sku IS NOT NULL)`),
	index("idx_product_projections_station").using("btree", table.stationId.asc().nullsLast().op("uuid_ops")).where(sql`(station_id IS NOT NULL)`),
	index("idx_product_projections_tenant").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops")),
	foreignKey({
			columns: [table.menuId],
			foreignColumns: [menus.id],
			name: "product_projections_menu_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.recipeId],
			foreignColumns: [recipes.id],
			name: "product_projections_recipe_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.stationId],
			foreignColumns: [stations.id],
			name: "product_projections_station_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "product_projections_tenant_id_fkey"
		}),
	pgPolicy("chef_product_projections", { as: "permissive", for: "all", to: ["public"], using: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))` }),
	check("product_projections_price_cents_check", sql`price_cents >= 0`),
]);

