export const platformSnapshots = pgTable("platform_snapshots", {
	id: uuid().defaultRandom().primaryKey().notNull(),
	tenantId: uuid("tenant_id").notNull(),
	platformRecordId: uuid("platform_record_id").notNull(),
	inquiryId: uuid("inquiry_id").notNull(),
	eventId: uuid("event_id"),
	captureType: text("capture_type").notNull(),
	source: text().default('capture').notNull(),
	pageUrl: text("page_url"),
	pageTitle: text("page_title"),
	summary: text(),
	textExcerpt: text("text_excerpt"),
	extractedClientName: text("extracted_client_name"),
	extractedEmail: text("extracted_email"),
	extractedPhone: text("extracted_phone"),
	extractedBookingDate: date("extracted_booking_date"),
	extractedGuestCount: integer("extracted_guest_count"),
	extractedLocation: text("extracted_location"),
	extractedOccasion: text("extracted_occasion"),
	extractedAmountCents: integer("extracted_amount_cents"),
	metadata: jsonb().default({}).notNull(),
	snapshotAt: timestamp("snapshot_at", { withTimezone: true, mode: 'string' }).default(sql`timezone('utc'::text, now())`).notNull(),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }).default(sql`timezone('utc'::text, now())`).notNull(),
	createdBy: uuid("created_by"),
}, (table) => [
	index("idx_platform_snapshots_record_snapshot").using("btree", table.platformRecordId.asc().nullsLast().op("timestamptz_ops"), table.snapshotAt.desc().nullsFirst().op("timestamptz_ops")),
	index("idx_platform_snapshots_tenant_platform").using("btree", table.tenantId.asc().nullsLast().op("uuid_ops"), table.inquiryId.asc().nullsLast().op("timestamptz_ops"), table.snapshotAt.desc().nullsFirst().op("uuid_ops")),
	foreignKey({
			columns: [table.eventId],
			foreignColumns: [events.id],
			name: "platform_snapshots_event_id_fkey"
		}).onDelete("set null"),
	foreignKey({
			columns: [table.inquiryId],
			foreignColumns: [inquiries.id],
			name: "platform_snapshots_inquiry_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.platformRecordId],
			foreignColumns: [platformRecords.id],
			name: "platform_snapshots_platform_record_id_fkey"
		}).onDelete("cascade"),
	foreignKey({
			columns: [table.tenantId],
			foreignColumns: [chefs.id],
			name: "platform_snapshots_tenant_id_fkey"
		}).onDelete("cascade"),
	pgPolicy("Chefs manage own platform snapshots", { as: "permissive", for: "all", to: ["public"], using: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`, withCheck: sql`(tenant_id IN ( SELECT user_roles.entity_id
   FROM user_roles
  WHERE ((user_roles.auth_user_id = auth.uid()) AND (user_roles.role = 'chef'::user_role))))`  }),
	pgPolicy("Service role manages platform snapshots", { as: "permissive", for: "all", to: ["public"] }),
	check("platform_snapshots_extracted_amount_cents_check", sql`(extracted_amount_cents IS NULL) OR (extracted_amount_cents >= 0)`),
]);

