export const eventTimeSummary = pgView("event_time_summary", {	eventId: uuid("event_id"),
	tenantId: uuid("tenant_id"),
	shoppingDurationMinutes: numeric("shopping_duration_minutes"),
	prepDurationMinutes: numeric("prep_duration_minutes"),
	travelDurationMinutes: numeric("travel_duration_minutes"),
	serviceDurationMinutes: numeric("service_duration_minutes"),
	resetDurationMinutes: numeric("reset_duration_minutes"),
	totalTimeMinutes: numeric("total_time_minutes"),
	totalTimeHours: numeric("total_time_hours"),
}).as(sql`SELECT events.id AS event_id, events.tenant_id, EXTRACT(epoch FROM events.shopping_completed_at - events.shopping_started_at) / 60::numeric AS shopping_duration_minutes, EXTRACT(epoch FROM events.prep_completed_at - events.prep_started_at) / 60::numeric AS prep_duration_minutes, EXTRACT(epoch FROM events.travel_completed_at - events.travel_started_at) / 60::numeric AS travel_duration_minutes, EXTRACT(epoch FROM events.service_completed_at - events.service_started_at) / 60::numeric AS service_duration_minutes, EXTRACT(epoch FROM events.reset_completed_at - events.reset_started_at) / 60::numeric AS reset_duration_minutes, (COALESCE(EXTRACT(epoch FROM events.shopping_completed_at - events.shopping_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM events.prep_completed_at - events.prep_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM events.travel_completed_at - events.travel_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM events.service_completed_at - events.service_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM events.reset_completed_at - events.reset_started_at), 0::numeric)) / 60::numeric AS total_time_minutes, (COALESCE(EXTRACT(epoch FROM events.shopping_completed_at - events.shopping_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM events.prep_completed_at - events.prep_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM events.travel_completed_at - events.travel_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM events.service_completed_at - events.service_started_at), 0::numeric) + COALESCE(EXTRACT(epoch FROM events.reset_completed_at - events.reset_started_at), 0::numeric)) / 3600::numeric AS total_time_hours FROM events`);

export const clientFinancialSummary = pgView("client_financial_summary", {	clientId: uuid("client_id"),
	tenantId: uuid("tenant_id"),
	lifetimeValueCents: integer("lifetime_value_cents"),
	totalEventsCount: integer("total_events_count"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalEventsCompleted: bigint("total_events_completed", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalEventsCancelled: bigint("total_events_cancelled", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	averageSpendPerEvent: bigint("average_spend_per_event", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalTipsGivenCents: bigint("total_tips_given_cents", { mode: "number" }),
	averageTipPercentage: numeric("average_tip_percentage"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	outstandingBalanceCents: bigint("outstanding_balance_cents", { mode: "number" }),
	lastEventDate: date("last_event_date"),
	firstEventDate: date("first_event_date"),
	daysSinceLastEvent: integer("days_since_last_event"),
	isDormant: boolean("is_dormant"),
}).as(sql`SELECT c.id AS client_id, c.tenant_id, c.lifetime_value_cents, c.total_events_count, count(e.id) FILTER (WHERE e.status = 'completed'::event_status) AS total_events_completed, count(e.id) FILTER (WHERE e.status = 'cancelled'::event_status) AS total_events_cancelled, CASE WHEN count(e.id) FILTER (WHERE e.status = 'completed'::event_status) > 0 THEN c.lifetime_value_cents / count(e.id) FILTER (WHERE e.status = 'completed'::event_status) ELSE 0::bigint END AS average_spend_per_event, COALESCE(sum(le.amount_cents) FILTER (WHERE le.entry_type = 'tip'::ledger_entry_type), 0::bigint) AS total_tips_given_cents, CASE WHEN c.lifetime_value_cents > 0 THEN COALESCE(sum(le.amount_cents) FILTER (WHERE le.entry_type = 'tip'::ledger_entry_type), 0::bigint)::numeric / c.lifetime_value_cents::numeric ELSE 0::numeric END AS average_tip_percentage, COALESCE(sum(e.quoted_price_cents) FILTER (WHERE e.payment_status <> 'paid'::payment_status), 0::bigint) AS outstanding_balance_cents, c.last_event_date, c.first_event_date, CURRENT_DATE - c.last_event_date AS days_since_last_event, (CURRENT_DATE - c.last_event_date) > 180 AS is_dormant FROM clients c LEFT JOIN events e ON e.client_id = c.id LEFT JOIN ledger_entries le ON le.client_id = c.id GROUP BY c.id`);

export const ingredientUsageSummary = pgView("ingredient_usage_summary", {	ingredientId: uuid("ingredient_id"),
	tenantId: uuid("tenant_id"),
	ingredientName: text("ingredient_name"),
	category: ingredientCategory(),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	timesUsed: bigint("times_used", { mode: "number" }),
	recipesUsing: text("recipes_using"),
	lastUsedInRecipeAt: timestamp("last_used_in_recipe_at", { withTimezone: true, mode: 'string' }),
}).as(sql`SELECT i.id AS ingredient_id, i.tenant_id, i.name AS ingredient_name, i.category, ( SELECT count(*) AS count FROM recipe_ingredients WHERE recipe_ingredients.ingredient_id = i.id) AS times_used, ( SELECT array_agg(DISTINCT r.name) AS array_agg FROM recipe_ingredients ri JOIN recipes r ON r.id = ri.recipe_id WHERE ri.ingredient_id = i.id) AS recipes_using, ( SELECT max(r.last_cooked_at) AS max FROM recipe_ingredients ri JOIN recipes r ON r.id = ri.recipe_id WHERE ri.ingredient_id = i.id) AS last_used_in_recipe_at FROM ingredients i WHERE i.archived = false`);

export const menuCostSummary = pgView("menu_cost_summary", {	menuId: uuid("menu_id"),
	tenantId: uuid("tenant_id"),
	eventId: uuid("event_id"),
	menuName: text("menu_name"),
	totalComponentCount: integer("total_component_count"),
	totalRecipeCostCents: integer("total_recipe_cost_cents"),
	costPerGuestCents: integer("cost_per_guest_cents"),
	foodCostPercentage: numeric("food_cost_percentage"),
	hasAllRecipeCosts: boolean("has_all_recipe_costs"),
}).as(sql`SELECT m.id AS menu_id, m.tenant_id, m.event_id, m.name AS menu_name, get_menu_total_component_count(m.id) AS total_component_count, compute_menu_cost_cents(m.id) AS total_recipe_cost_cents, CASE WHEN e.guest_count > 0 THEN compute_menu_cost_cents(m.id) / e.guest_count ELSE NULL::integer END AS cost_per_guest_cents, CASE WHEN e.quoted_price_cents > 0 THEN (compute_menu_cost_cents(m.id)::numeric / e.quoted_price_cents::numeric * 100::numeric)::numeric(5,2) ELSE NULL::numeric END AS food_cost_percentage, ( SELECT count(*) = count(c.recipe_id) FROM components c JOIN dishes d ON d.id = c.dish_id WHERE d.menu_id = m.id) AS has_all_recipe_costs FROM menus m LEFT JOIN events e ON e.id = m.event_id`);

export const dishComponentSummary = pgView("dish_component_summary", {	dishId: uuid("dish_id"),
	tenantId: uuid("tenant_id"),
	menuId: uuid("menu_id"),
	courseNumber: integer("course_number"),
	courseName: text("course_name"),
	componentCount: integer("component_count"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	makeAheadCount: bigint("make_ahead_count", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	componentsWithRecipes: bigint("components_with_recipes", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	componentsWithoutRecipes: bigint("components_without_recipes", { mode: "number" }),
}).as(sql`SELECT d.id AS dish_id, d.tenant_id, d.menu_id, d.course_number, d.course_name, get_dish_component_count(d.id) AS component_count, ( SELECT count(*) AS count FROM components WHERE components.dish_id = d.id AND components.is_make_ahead = true) AS make_ahead_count, ( SELECT count(*) AS count FROM components WHERE components.dish_id = d.id AND components.recipe_id IS NOT NULL) AS components_with_recipes, ( SELECT count(*) AS count FROM components WHERE components.dish_id = d.id AND components.recipe_id IS NULL) AS components_without_recipes FROM dishes d`);

export const unifiedInbox = pgView("unified_inbox", {	id: uuid(),
	tenantId: uuid("tenant_id"),
	source: text(),
	preview: text(),
	activityAt: timestamp("activity_at", { withTimezone: true, mode: 'string' }),
	actorId: uuid("actor_id"),
	conversationId: uuid("conversation_id"),
	inquiryId: uuid("inquiry_id"),
	eventId: uuid("event_id"),
	clientId: uuid("client_id"),
	contentType: text("content_type"),
	isRead: boolean("is_read"),
}).as(sql`SELECT c.id, c.tenant_id, 'chat'::text AS source, c.last_message_preview AS preview, COALESCE(c.last_message_at, c.created_at) AS activity_at, c.last_message_sender_id AS actor_id, NULL::uuid AS conversation_id, c.inquiry_id, c.event_id, NULL::uuid AS client_id, c.context_type::text AS content_type, false AS is_read FROM conversations c WHERE c.last_message_at IS NOT NULL UNION ALL SELECT m.id, m.tenant_id, 'message'::text AS source, CASE WHEN m.subject IS NOT NULL AND m.subject <> ''::text THEN (m.subject || ': '::text) || "left"(m.body, 150) ELSE "left"(m.body, 200) END AS preview, COALESCE(m.sent_at, m.created_at) AS activity_at, m.from_user_id AS actor_id, NULL::uuid AS conversation_id, m.inquiry_id, m.event_id, m.client_id, m.channel::text AS content_type, false AS is_read FROM messages m WHERE m.status = ANY (ARRAY['sent'::message_status, 'logged'::message_status]) UNION ALL SELECT ws.id, ws.tenant_id, 'wix'::text AS source, CASE WHEN ws.submitter_name IS NOT NULL THEN ws.submitter_name || ' submitted a form'::text WHEN ws.submitter_email IS NOT NULL THEN ws.submitter_email || ' submitted a form'::text ELSE 'New Wix form submission'::text END AS preview, ws.created_at AS activity_at, NULL::uuid AS actor_id, NULL::uuid AS conversation_id, ws.inquiry_id, NULL::uuid AS event_id, ws.client_id, 'wix_form'::text AS content_type, ws.status = 'completed'::text AS is_read FROM wix_submissions ws UNION ALL SELECT n.id, n.tenant_id, 'notification'::text AS source, COALESCE(n.body, n.title) AS preview, n.created_at AS activity_at, NULL::uuid AS actor_id, NULL::uuid AS conversation_id, n.inquiry_id, n.event_id, n.client_id, n.action AS content_type, n.read_at IS NOT NULL AS is_read FROM notifications n WHERE n.archived_at IS NULL`);

export const communicationInboxItems = pgView("communication_inbox_items", {	threadId: uuid("thread_id"),
	tenantId: uuid("tenant_id"),
	clientId: uuid("client_id"),
	lastActivityAt: timestamp("last_activity_at", { withTimezone: true, mode: 'string' }),
	threadState: conversationThreadState("thread_state"),
	snoozedUntil: timestamp("snoozed_until", { withTimezone: true, mode: 'string' }),
	communicationEventId: uuid("communication_event_id"),
	eventTimestamp: timestamp("event_timestamp", { withTimezone: true, mode: 'string' }),
	senderIdentity: text("sender_identity"),
	source: communicationSource(),
	direction: communicationDirection(),
	rawContent: text("raw_content"),
	normalizedContent: text("normalized_content"),
	communicationStatus: communicationEventStatus("communication_status"),
	linkedEntityType: text("linked_entity_type"),
	linkedEntityId: uuid("linked_entity_id"),
	resolvedClientId: uuid("resolved_client_id"),
	nextFollowUpDueAt: timestamp("next_follow_up_due_at", { withTimezone: true, mode: 'string' }),
	hasOverdueFollowUp: boolean("has_overdue_follow_up"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	pendingLinkCount: bigint("pending_link_count", { mode: "number" }),
	topPendingConfidence: numeric("top_pending_confidence"),
	tab: text(),
	needsAttention: boolean("needs_attention"),
	isStarred: boolean("is_starred"),
}).as(sql`WITH latest_event AS ( SELECT DISTINCT ON (ce.thread_id) ce.id AS communication_event_id, ce.tenant_id, ce.thread_id, ce."timestamp", ce.sender_identity, ce.source, ce.direction, ce.raw_content, ce.normalized_content, ce.status AS communication_status, ce.linked_entity_type, ce.linked_entity_id, ce.resolved_client_id FROM communication_events ce ORDER BY ce.thread_id, ce."timestamp" DESC, ce.created_at DESC ), overdue_timer AS ( SELECT fut.thread_id, min(fut.due_at) AS next_due_at, bool_or(fut.status = 'active'::follow_up_timer_status AND fut.due_at <= now()) AS has_overdue FROM follow_up_timers fut GROUP BY fut.thread_id ), pending_links AS ( SELECT sl.communication_event_id, count(*) FILTER (WHERE sl.status = 'pending'::suggested_link_status) AS pending_link_count, max(sl.confidence_score) FILTER (WHERE sl.status = 'pending'::suggested_link_status) AS top_pending_confidence FROM suggested_links sl GROUP BY sl.communication_event_id ) SELECT ct.id AS thread_id, ct.tenant_id, ct.client_id, ct.last_activity_at, ct.state AS thread_state, ct.snoozed_until, le.communication_event_id, le."timestamp" AS event_timestamp, le.sender_identity, le.source, le.direction, le.raw_content, le.normalized_content, le.communication_status, le.linked_entity_type, le.linked_entity_id, le.resolved_client_id, COALESCE(ot.next_due_at, NULL::timestamp with time zone) AS next_follow_up_due_at, COALESCE(ot.has_overdue, false) AS has_overdue_follow_up, COALESCE(pl.pending_link_count, 0::bigint) AS pending_link_count, COALESCE(pl.top_pending_confidence, 0::numeric) AS top_pending_confidence, CASE WHEN ct.state = 'snoozed'::conversation_thread_state AND (ct.snoozed_until IS NULL OR ct.snoozed_until > now()) THEN 'snoozed'::text WHEN le.communication_status = 'resolved'::communication_event_status OR ct.state = 'closed'::conversation_thread_state THEN 'resolved'::text WHEN le.communication_status = 'unlinked'::communication_event_status THEN 'unlinked'::text ELSE 'needs_attention'::text END AS tab, COALESCE(ot.has_overdue, false) = true AND ct.state = 'active'::conversation_thread_state OR le.communication_status = 'unlinked'::communication_event_status AND ct.state = 'active'::conversation_thread_state OR COALESCE(pl.pending_link_count, 0::bigint) > 0 AND ct.state = 'active'::conversation_thread_state AS needs_attention, ct.is_starred FROM conversation_threads ct JOIN latest_event le ON le.thread_id = ct.id LEFT JOIN overdue_timer ot ON ot.thread_id = ct.id LEFT JOIN pending_links pl ON pl.communication_event_id = le.communication_event_id`);

export const guestFeedbackSummary = pgView("guest_feedback_summary", {	eventId: uuid("event_id"),
	tenantId: uuid("tenant_id"),
	submittedCount: integer("submitted_count"),
	pendingCount: integer("pending_count"),
	totalSent: integer("total_sent"),
	avgOverall: numeric("avg_overall"),
	avgFood: numeric("avg_food"),
	avgExperience: numeric("avg_experience"),
	testimonialCount: integer("testimonial_count"),
}).as(sql`SELECT gf.event_id, gf.tenant_id, count(*) FILTER (WHERE gf.submitted_at IS NOT NULL)::integer AS submitted_count, count(*) FILTER (WHERE gf.submitted_at IS NULL AND gf.sent_at IS NOT NULL)::integer AS pending_count, count(*)::integer AS total_sent, round(avg(gf.overall_rating) FILTER (WHERE gf.submitted_at IS NOT NULL), 2) AS avg_overall, round(avg(gf.food_rating) FILTER (WHERE gf.submitted_at IS NOT NULL), 2) AS avg_food, round(avg(gf.experience_rating) FILTER (WHERE gf.submitted_at IS NOT NULL), 2) AS avg_experience, count(*) FILTER (WHERE gf.testimonial_consent = true)::integer AS testimonial_count FROM guest_feedback gf GROUP BY gf.event_id, gf.tenant_id`);

export const dishIndexSummary = pgView("dish_index_summary", {	id: uuid(),
	tenantId: uuid("tenant_id"),
	name: text(),
	course: text(),
	description: text(),
	dietaryTags: text("dietary_tags"),
	allergenFlags: text("allergen_flags"),
	timesServed: integer("times_served"),
	firstServed: date("first_served"),
	lastServed: date("last_served"),
	isSignature: boolean("is_signature"),
	rotationStatus: dishRotationStatus("rotation_status"),
	linkedRecipeId: uuid("linked_recipe_id"),
	prepComplexity: dishPrepComplexity("prep_complexity"),
	platingDifficulty: dishPlatingDifficulty("plating_difficulty"),
	tags: text(),
	seasonAffinity: text("season_affinity"),
	archived: boolean(),
	recipeName: text("recipe_name"),
	recipeCostCents: integer("recipe_cost_cents"),
	perPortionCostCents: integer("per_portion_cost_cents"),
	avgRating: numeric("avg_rating"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	feedbackCount: bigint("feedback_count", { mode: "number" }),
}).as(sql`SELECT di.id, di.tenant_id, di.name, di.course, di.description, di.dietary_tags, di.allergen_flags, di.times_served, di.first_served, di.last_served, di.is_signature, di.rotation_status, di.linked_recipe_id, di.prep_complexity, di.plating_difficulty, di.tags, di.season_affinity, di.archived, r.name AS recipe_name, rcs.total_ingredient_cost_cents AS recipe_cost_cents, rcs.cost_per_portion_cents AS per_portion_cost_cents, COALESCE(fb.avg_rating, 0::numeric) AS avg_rating, COALESCE(fb.feedback_count, 0::bigint) AS feedback_count FROM dish_index di LEFT JOIN recipes r ON r.id = di.linked_recipe_id LEFT JOIN recipe_cost_summary rcs ON rcs.recipe_id = di.linked_recipe_id LEFT JOIN ( SELECT dish_feedback.dish_id, avg(dish_feedback.rating)::numeric(3,1) AS avg_rating, count(*) AS feedback_count FROM dish_feedback GROUP BY dish_feedback.dish_id) fb ON fb.dish_id = di.id`);

export const inventoryCurrentStock = pgView("inventory_current_stock", {	chefId: uuid("chef_id"),
	ingredientId: uuid("ingredient_id"),
	ingredientName: text("ingredient_name"),
	unit: text(),
	currentQty: numeric("current_qty"),
	parLevel: numeric("par_level", { precision: 10, scale:  3 }),
	vendorId: uuid("vendor_id"),
	lastMovementAt: timestamp("last_movement_at", { withTimezone: true, mode: 'string' }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	transactionCount: bigint("transaction_count", { mode: "number" }),
}).as(sql`SELECT it.chef_id, it.ingredient_id, max(it.ingredient_name) AS ingredient_name, it.unit, sum(it.quantity) AS current_qty, ic.par_level, ic.vendor_id, max(it.created_at) AS last_movement_at, count(*) AS transaction_count FROM inventory_transactions it LEFT JOIN inventory_counts ic ON ic.chef_id = it.chef_id AND ic.ingredient_id = it.ingredient_id GROUP BY it.chef_id, it.ingredient_id, it.unit, ic.par_level, ic.vendor_id`);

export const inventoryByLocation = pgView("inventory_by_location", {	chefId: uuid("chef_id"),
	locationId: uuid("location_id"),
	locationName: text("location_name"),
	locationType: storageLocationType("location_type"),
	ingredientId: uuid("ingredient_id"),
	ingredientName: text("ingredient_name"),
	unit: text(),
	currentQty: numeric("current_qty"),
}).as(sql`SELECT it.chef_id, it.location_id, sl.name AS location_name, sl.location_type, it.ingredient_id, max(it.ingredient_name) AS ingredient_name, it.unit, sum(it.quantity) AS current_qty FROM inventory_transactions it LEFT JOIN storage_locations sl ON sl.id = it.location_id WHERE it.location_id IS NOT NULL GROUP BY it.chef_id, it.location_id, sl.name, sl.location_type, it.ingredient_id, it.unit HAVING sum(it.quantity) <> 0::numeric`);

export const upcomingIngredientDemand = pgView("upcoming_ingredient_demand", {	chefId: uuid("chef_id"),
	ingredientId: uuid("ingredient_id"),
	ingredientName: text("ingredient_name"),
	unit: text(),
	totalNeededQty: numeric("total_needed_qty"),
	lastPriceCents: integer("last_price_cents"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	eventCount: bigint("event_count", { mode: "number" }),
	firstEventDate: date("first_event_date"),
	events: text(),
}).as(sql`WITH upcoming_events AS ( SELECT e.id AS event_id, e.tenant_id, e.event_date, e.guest_count, e.occasion FROM events e WHERE (e.status = ANY (ARRAY['confirmed'::event_status, 'paid'::event_status])) AND e.event_date >= CURRENT_DATE AND e.event_date <= (CURRENT_DATE + '30 days'::interval) ), event_ingredients AS ( SELECT ue.tenant_id AS chef_id, ue.event_id, ue.event_date, ue.occasion, i.id AS ingredient_id, i.name AS ingredient_name, ri.unit, sum(ri.quantity * COALESCE(c.scale_factor, 1::numeric)) AS needed_qty, i.last_price_cents FROM upcoming_events ue JOIN menus m ON m.event_id = ue.event_id JOIN dishes d ON d.menu_id = m.id JOIN components c ON c.dish_id = d.id AND c.recipe_id IS NOT NULL JOIN recipe_ingredients ri ON ri.recipe_id = c.recipe_id JOIN ingredients i ON i.id = ri.ingredient_id WHERE NOT i.is_staple GROUP BY ue.tenant_id, ue.event_id, ue.event_date, ue.occasion, i.id, i.name, ri.unit, i.last_price_cents ) SELECT ei.chef_id, ei.ingredient_id, ei.ingredient_name, ei.unit, sum(ei.needed_qty) AS total_needed_qty, ei.last_price_cents, count(DISTINCT ei.event_id) AS event_count, min(ei.event_date) AS first_event_date, array_agg(DISTINCT ei.occasion) AS events FROM event_ingredients ei GROUP BY ei.chef_id, ei.ingredient_id, ei.ingredient_name, ei.unit, ei.last_price_cents`);

export const inventoryExpiryAlerts = pgView("inventory_expiry_alerts", {	chefId: uuid("chef_id"),
	batchId: uuid("batch_id"),
	ingredientId: uuid("ingredient_id"),
	ingredientName: text("ingredient_name"),
	expiryDate: date("expiry_date"),
	remainingQty: numeric("remaining_qty", { precision: 10, scale:  3 }),
	unit: text(),
	unitCostCents: integer("unit_cost_cents"),
	atRiskCostCents: integer("at_risk_cost_cents"),
	locationName: text("location_name"),
	urgency: text(),
}).as(sql`SELECT ib.chef_id, ib.id AS batch_id, ib.ingredient_id, ib.ingredient_name, ib.expiry_date, ib.remaining_qty, ib.unit, ib.unit_cost_cents, (ib.remaining_qty * COALESCE(ib.unit_cost_cents, 0)::numeric)::integer AS at_risk_cost_cents, sl.name AS location_name, CASE WHEN ib.expiry_date <= CURRENT_DATE THEN 'expired'::text WHEN ib.expiry_date <= (CURRENT_DATE + 3) THEN 'critical'::text WHEN ib.expiry_date <= (CURRENT_DATE + 7) THEN 'warning'::text ELSE 'ok'::text END AS urgency FROM inventory_batches ib LEFT JOIN storage_locations sl ON sl.id = ib.location_id WHERE NOT ib.is_depleted AND ib.expiry_date IS NOT NULL AND ib.expiry_date <= (CURRENT_DATE + '7 days'::interval)`);

export const eventInventoryVariance = pgView("event_inventory_variance", {	eventId: uuid("event_id"),
	chefId: uuid("chef_id"),
	ingredientId: uuid("ingredient_id"),
	ingredientName: text("ingredient_name"),
	unit: text(),
	expectedQty: numeric("expected_qty"),
	actualQty: numeric("actual_qty"),
	varianceQty: numeric("variance_qty"),
	lastPriceCents: integer("last_price_cents"),
	varianceCostCents: integer("variance_cost_cents"),
}).as(sql`WITH expected_usage AS ( SELECT e.id AS event_id, e.tenant_id AS chef_id, i.id AS ingredient_id, i.name AS ingredient_name, ri.unit, sum(ri.quantity * COALESCE(c.scale_factor, 1::numeric)) AS expected_qty, i.last_price_cents FROM events e JOIN menus m ON m.event_id = e.id JOIN dishes d ON d.menu_id = m.id JOIN components c ON c.dish_id = d.id AND c.recipe_id IS NOT NULL JOIN recipe_ingredients ri ON ri.recipe_id = c.recipe_id JOIN ingredients i ON i.id = ri.ingredient_id WHERE e.status = ANY (ARRAY['completed'::event_status, 'in_progress'::event_status]) GROUP BY e.id, e.tenant_id, i.id, i.name, ri.unit, i.last_price_cents ), actual_usage AS ( SELECT it.event_id, it.chef_id, it.ingredient_id, max(it.ingredient_name) AS ingredient_name, it.unit, abs(sum(it.quantity)) AS actual_qty FROM inventory_transactions it WHERE it.event_id IS NOT NULL AND it.transaction_type = 'event_deduction'::inventory_transaction_type GROUP BY it.event_id, it.chef_id, it.ingredient_id, it.unit ) SELECT eu.event_id, eu.chef_id, eu.ingredient_id, eu.ingredient_name, eu.unit, eu.expected_qty, COALESCE(au.actual_qty, 0::numeric) AS actual_qty, COALESCE(au.actual_qty, 0::numeric) - eu.expected_qty AS variance_qty, eu.last_price_cents, ((COALESCE(au.actual_qty, 0::numeric) - eu.expected_qty) * COALESCE(eu.last_price_cents, 0)::numeric)::integer AS variance_cost_cents FROM expected_usage eu LEFT JOIN actual_usage au ON eu.event_id = au.event_id AND eu.ingredient_id = au.ingredient_id`);

export const saleFinancialSummary = pgView("sale_financial_summary", {	saleId: uuid("sale_id"),
	tenantId: uuid("tenant_id"),
	saleNumber: text("sale_number"),
	status: saleStatus(),
	channel: saleChannel(),
	totalCents: integer("total_cents"),
	taxCents: integer("tax_cents"),
	tipCents: integer("tip_cents"),
	discountCents: integer("discount_cents"),
	subtotalCents: integer("subtotal_cents"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalPaidCents: bigint("total_paid_cents", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalTipsCents: bigint("total_tips_cents", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalRefundedCents: bigint("total_refunded_cents", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	balanceDueCents: bigint("balance_due_cents", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalCostCents: bigint("total_cost_cents", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	grossProfitCents: bigint("gross_profit_cents", { mode: "number" }),
	createdAt: timestamp("created_at", { withTimezone: true, mode: 'string' }),
	eventId: uuid("event_id"),
	clientId: uuid("client_id"),
}).as(sql`SELECT s.id AS sale_id, s.tenant_id, s.sale_number, s.status, s.channel, s.total_cents, s.tax_cents, s.tip_cents, s.discount_cents, s.subtotal_cents, COALESCE(pay.total_paid_cents, 0::bigint) AS total_paid_cents, COALESCE(pay.total_tips_cents, 0::bigint) AS total_tips_cents, COALESCE(ref.total_refunded_cents, 0::bigint) AS total_refunded_cents, s.total_cents - COALESCE(pay.total_paid_cents, 0::bigint) + COALESCE(ref.total_refunded_cents, 0::bigint) AS balance_due_cents, COALESCE(cost.total_cost_cents, 0::bigint) AS total_cost_cents, s.total_cents - COALESCE(cost.total_cost_cents, 0::bigint) AS gross_profit_cents, s.created_at, s.event_id, s.client_id FROM sales s LEFT JOIN LATERAL ( SELECT sum(commerce_payments.amount_cents) FILTER (WHERE commerce_payments.status = ANY (ARRAY['captured'::commerce_payment_status, 'settled'::commerce_payment_status])) AS total_paid_cents, sum(commerce_payments.tip_cents) FILTER (WHERE commerce_payments.status = ANY (ARRAY['captured'::commerce_payment_status, 'settled'::commerce_payment_status])) AS total_tips_cents FROM commerce_payments WHERE commerce_payments.sale_id = s.id) pay ON true LEFT JOIN LATERAL ( SELECT sum(commerce_refunds.amount_cents) FILTER (WHERE commerce_refunds.status = 'processed'::refund_status) AS total_refunded_cents FROM commerce_refunds WHERE commerce_refunds.sale_id = s.id) ref ON true LEFT JOIN LATERAL ( SELECT sum(sale_items.unit_cost_cents * sale_items.quantity) AS total_cost_cents FROM sale_items WHERE sale_items.sale_id = s.id AND sale_items.unit_cost_cents IS NOT NULL) cost ON true`);

export const eventRsvpSummary = pgView("event_rsvp_summary", {	eventId: uuid("event_id"),
	tenantId: uuid("tenant_id"),
	totalGuests: integer("total_guests"),
	attendingCount: integer("attending_count"),
	declinedCount: integer("declined_count"),
	maybeCount: integer("maybe_count"),
	pendingCount: integer("pending_count"),
	waitlistedCount: integer("waitlisted_count"),
	plusOneCount: integer("plus_one_count"),
	allDietaryRestrictions: text("all_dietary_restrictions"),
	allAllergies: text("all_allergies"),
}).as(sql`SELECT eg.event_id, eg.tenant_id, count(*)::integer AS total_guests, count(*) FILTER (WHERE eg.rsvp_status = 'attending'::rsvp_status)::integer AS attending_count, count(*) FILTER (WHERE eg.rsvp_status = 'declined'::rsvp_status)::integer AS declined_count, count(*) FILTER (WHERE eg.rsvp_status = 'maybe'::rsvp_status)::integer AS maybe_count, count(*) FILTER (WHERE eg.rsvp_status = 'pending'::rsvp_status AND COALESCE(eg.attendance_queue_status, 'none'::text) <> 'waitlisted'::text)::integer AS pending_count, count(*) FILTER (WHERE COALESCE(eg.attendance_queue_status, 'none'::text) = 'waitlisted'::text)::integer AS waitlisted_count, count(*) FILTER (WHERE eg.plus_one = true)::integer AS plus_one_count, ARRAY( SELECT DISTINCT unnest(eg2.dietary_restrictions) AS unnest FROM event_guests eg2 WHERE eg2.event_id = eg.event_id AND (eg2.rsvp_status = ANY (ARRAY['attending'::rsvp_status, 'maybe'::rsvp_status])) AND eg2.dietary_restrictions <> '{}'::text[]) AS all_dietary_restrictions, ARRAY( SELECT DISTINCT unnest(eg2.allergies) AS unnest FROM event_guests eg2 WHERE eg2.event_id = eg.event_id AND (eg2.rsvp_status = ANY (ARRAY['attending'::rsvp_status, 'maybe'::rsvp_status])) AND eg2.allergies <> '{}'::text[]) AS all_allergies FROM event_guests eg GROUP BY eg.event_id, eg.tenant_id`);

export const ingredientMonthlyPriceAvg = pgView("ingredient_monthly_price_avg", {	tenantId: uuid("tenant_id"),
	ingredientId: uuid("ingredient_id"),
	year: integer(),
	month: integer(),
	avgPriceCents: integer("avg_price_cents"),
	minPriceCents: integer("min_price_cents"),
	maxPriceCents: integer("max_price_cents"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	dataPoints: bigint("data_points", { mode: "number" }),
}).as(sql`SELECT ingredient_price_history.tenant_id, ingredient_price_history.ingredient_id, EXTRACT(year FROM ingredient_price_history.purchase_date)::integer AS year, EXTRACT(month FROM ingredient_price_history.purchase_date)::integer AS month, round(avg(ingredient_price_history.price_cents))::integer AS avg_price_cents, min(ingredient_price_history.price_cents) AS min_price_cents, max(ingredient_price_history.price_cents) AS max_price_cents, count(*) AS data_points FROM ingredient_price_history GROUP BY ingredient_price_history.tenant_id, ingredient_price_history.ingredient_id, (EXTRACT(year FROM ingredient_price_history.purchase_date)), (EXTRACT(month FROM ingredient_price_history.purchase_date))`);

export const ingredientBestVendorPrice = pgView("ingredient_best_vendor_price", {	chefId: uuid("chef_id"),
	ingredientName: text("ingredient_name"),
	ingredientId: uuid("ingredient_id"),
	vendorId: uuid("vendor_id"),
	unitPriceCents: integer("unit_price_cents"),
	priceUnit: text("price_unit"),
	leadTimeDays: integer("lead_time_days"),
	minOrderQty: numeric("min_order_qty", { precision: 10, scale:  3 }),
	minOrderUnit: text("min_order_unit"),
	isPreferred: boolean("is_preferred"),
}).as(sql`SELECT DISTINCT ON (vendor_preferred_ingredients.chef_id, vendor_preferred_ingredients.ingredient_name) vendor_preferred_ingredients.chef_id, vendor_preferred_ingredients.ingredient_name, vendor_preferred_ingredients.ingredient_id, vendor_preferred_ingredients.vendor_id, vendor_preferred_ingredients.unit_price_cents, vendor_preferred_ingredients.price_unit, vendor_preferred_ingredients.lead_time_days, vendor_preferred_ingredients.min_order_qty, vendor_preferred_ingredients.min_order_unit, vendor_preferred_ingredients.is_preferred FROM vendor_preferred_ingredients WHERE vendor_preferred_ingredients.unit_price_cents IS NOT NULL ORDER BY vendor_preferred_ingredients.chef_id, vendor_preferred_ingredients.ingredient_name, vendor_preferred_ingredients.unit_price_cents`);

export const recipeCostSummary = pgView("recipe_cost_summary", {	recipeId: uuid("recipe_id"),
	tenantId: uuid("tenant_id"),
	recipeName: text("recipe_name"),
	category: recipeCategory(),
	totalIngredientCostCents: integer("total_ingredient_cost_cents"),
	costPerPortionCents: integer("cost_per_portion_cents"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	ingredientCount: bigint("ingredient_count", { mode: "number" }),
	hasAllPrices: boolean("has_all_prices"),
	lastPriceUpdatedAt: date("last_price_updated_at"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	subRecipeCount: bigint("sub_recipe_count", { mode: "number" }),
	avgPriceConfidence: numeric("avg_price_confidence"),
	minPriceConfidence: numeric("min_price_confidence"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	lowConfidenceCount: bigint("low_confidence_count", { mode: "number" }),
}).as(sql`SELECT r.id AS recipe_id, r.tenant_id, r.name AS recipe_name, r.category, COALESCE(r.total_cost_cents, compute_recipe_cost_cents(r.id)) AS total_ingredient_cost_cents, COALESCE(r.cost_per_serving_cents, CASE WHEN r.yield_quantity > 0::numeric THEN (compute_recipe_cost_cents(r.id)::numeric / r.yield_quantity)::integer ELSE NULL::integer END) AS cost_per_portion_cents, ( SELECT count(*) AS count FROM recipe_ingredients WHERE recipe_ingredients.recipe_id = r.id) AS ingredient_count, ( SELECT count(*) = count(COALESCE(i.cost_per_unit_cents, i.last_price_cents)) FROM recipe_ingredients ri JOIN ingredients i ON i.id = ri.ingredient_id WHERE ri.recipe_id = r.id) AS has_all_prices, ( SELECT max(i.last_price_date) AS max FROM recipe_ingredients ri JOIN ingredients i ON i.id = ri.ingredient_id WHERE ri.recipe_id = r.id) AS last_price_updated_at, ( SELECT count(*) AS count FROM recipe_sub_recipes WHERE recipe_sub_recipes.parent_recipe_id = r.id) AS sub_recipe_count, ( SELECT round(avg(i.last_price_confidence), 2) AS round FROM recipe_ingredients ri JOIN ingredients i ON i.id = ri.ingredient_id WHERE ri.recipe_id = r.id AND i.last_price_confidence IS NOT NULL) AS avg_price_confidence, ( SELECT min(i.last_price_confidence) AS min FROM recipe_ingredients ri JOIN ingredients i ON i.id = ri.ingredient_id WHERE ri.recipe_id = r.id AND i.last_price_confidence IS NOT NULL) AS min_price_confidence, ( SELECT count(*) AS count FROM recipe_ingredients ri JOIN ingredients i ON i.id = ri.ingredient_id WHERE ri.recipe_id = r.id AND i.last_price_confidence IS NOT NULL AND i.last_price_confidence < 0.5) AS low_confidence_count FROM recipes r WHERE r.archived = false`);

export const regionalPriceAverages = pgMaterializedView("regional_price_averages", {	ingredientId: uuid("ingredient_id"),
	ingredientName: text("ingredient_name"),
	category: ingredientCategory(),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	storeCount: bigint("store_count", { mode: "number" }),
	avgPricePerUnitCents: numeric("avg_price_per_unit_cents"),
	minPricePerUnitCents: integer("min_price_per_unit_cents"),
	maxPricePerUnitCents: integer("max_price_per_unit_cents"),
	mostCommonUnit: text("most_common_unit"),
	mostRecentDate: date("most_recent_date"),
}).as(sql`SELECT iph.ingredient_id, i.name AS ingredient_name, i.category, count(DISTINCT iph.store_name) AS store_count, round(avg(iph.price_per_unit_cents)) AS avg_price_per_unit_cents, min(iph.price_per_unit_cents) AS min_price_per_unit_cents, max(iph.price_per_unit_cents) AS max_price_per_unit_cents, mode() WITHIN GROUP (ORDER BY iph.unit) AS most_common_unit, max(iph.purchase_date) AS most_recent_date FROM ingredient_price_history iph JOIN ingredients i ON i.id = iph.ingredient_id WHERE iph.source ~~ 'openclaw_%'::text AND iph.purchase_date > (CURRENT_DATE - '60 days'::interval) AND iph.price_per_unit_cents > 0 AND iph.price_per_unit_cents < 50000 GROUP BY iph.ingredient_id, i.name, i.category HAVING count(DISTINCT iph.store_name) >= 2`);

export const categoryPriceBaselines = pgMaterializedView("category_price_baselines", {	category: ingredientCategory(),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	ingredientCount: bigint("ingredient_count", { mode: "number" }),
	avgCentsPerUnit: numeric("avg_cents_per_unit"),
	medianCentsPerUnit: doublePrecision("median_cents_per_unit"),
	mostCommonUnit: text("most_common_unit"),
}).as(sql`SELECT combined.category, count(DISTINCT combined.ingredient_id) AS ingredient_count, round(avg(combined.price_cents)) AS avg_cents_per_unit, percentile_cont(0.5::double precision) WITHIN GROUP (ORDER BY (combined.price_cents::double precision)) AS median_cents_per_unit, mode() WITHIN GROUP (ORDER BY combined.unit) AS most_common_unit FROM ( SELECT i.category, iph.ingredient_id, iph.price_per_unit_cents AS price_cents, iph.unit FROM ingredient_price_history iph JOIN ingredients i ON i.id = iph.ingredient_id WHERE iph.source ~~ 'openclaw_%'::text AND iph.purchase_date > (CURRENT_DATE - '90 days'::interval) AND iph.price_per_unit_cents > 0 AND iph.price_per_unit_cents < 50000 UNION ALL SELECT si.category, si.id AS ingredient_id, sip.median_price_cents AS price_cents, sip.price_unit AS unit FROM system_ingredients si JOIN openclaw.system_ingredient_prices sip ON sip.system_ingredient_id = si.id WHERE sip.median_price_cents > 0 AND sip.median_price_cents < 50000) combined GROUP BY combined.category HAVING count(DISTINCT combined.ingredient_id) >= 3`);

export const eventFinancialSummary = pgView("event_financial_summary", {	eventId: uuid("event_id"),
	tenantId: uuid("tenant_id"),
	quotedPriceCents: integer("quoted_price_cents"),
	paymentStatus: paymentStatus("payment_status"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalPaidCents: bigint("total_paid_cents", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalRefundedCents: bigint("total_refunded_cents", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	netRevenueCents: bigint("net_revenue_cents", { mode: "number" }),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	totalExpensesCents: bigint("total_expenses_cents", { mode: "number" }),
	tipAmountCents: integer("tip_amount_cents"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	profitCents: bigint("profit_cents", { mode: "number" }),
	profitMargin: numeric("profit_margin"),
	foodCostPercentage: numeric("food_cost_percentage"),
	// You can use { mode: "bigint" } if numbers are exceeding js number limitations
	outstandingBalanceCents: bigint("outstanding_balance_cents", { mode: "number" }),
}).as(sql`SELECT base.event_id, base.tenant_id, base.quoted_price_cents, base.payment_status, base.total_paid_cents, base.total_refunded_cents, base.net_revenue_cents, base.total_expenses_cents, base.tip_amount_cents, base.net_revenue_cents - base.total_expenses_cents AS profit_cents, CASE WHEN base.net_revenue_cents > 0 THEN (base.net_revenue_cents - base.total_expenses_cents)::numeric / base.net_revenue_cents::numeric ELSE 0::numeric END AS profit_margin, CASE WHEN base.net_revenue_cents > 0 THEN base.total_expenses_cents::numeric / base.net_revenue_cents::numeric ELSE 0::numeric END AS food_cost_percentage, base.quoted_price_cents - base.total_paid_cents AS outstanding_balance_cents FROM ( SELECT e.id AS event_id, e.tenant_id, e.quoted_price_cents, e.payment_status, e.tip_amount_cents, COALESCE(( SELECT sum(le.amount_cents) AS sum FROM ledger_entries le WHERE le.event_id = e.id AND le.is_refund = false AND le.entry_type <> 'tip'::ledger_entry_type), 0::bigint) AS total_paid_cents, COALESCE(( SELECT sum(abs(le.amount_cents)) AS sum FROM ledger_entries le WHERE le.event_id = e.id AND le.is_refund = true), 0::bigint) AS total_refunded_cents, COALESCE(( SELECT sum(le.amount_cents) AS sum FROM ledger_entries le WHERE le.event_id = e.id), 0::bigint) AS net_revenue_cents, COALESCE(( SELECT sum(ex.amount_cents) AS sum FROM expenses ex WHERE ex.event_id = e.id), 0::bigint) AS total_expenses_cents FROM events e WHERE e.deleted_at IS NULL) base`);
